  "query PullRequestDetail($owner: String!, $name: String!, $number: Int!, $filesFirst: Int!, $reviewsFirst: Int!, $threadsFirst: Int!, $commitsFirst: Int!) {\n  repository(owner: $owner, name: $name) {\n    id\n    name\n    nameWithOwner\n    url\n    pullRequest(number: $number) {\n      id\n      number\n      title\n      url\n      state\n      isDraft\n      createdAt\n      updatedAt\n      mergedAt\n      closedAt\n      additions\n      deletions\n      changedFiles\n      body\n      reviewDecision\n      mergeable\n      mergeStateStatus\n      baseRefName\n      headRefName\n      comments {\n        totalCount\n      }\n      commits(first: $commitsFirst) {\n        totalCount\n        nodes {\n          id\n          commit {\n            oid\n            committedDate\n            messageHeadline\n            authors(first: 2) {\n              nodes {\n                name\n                email\n                user {\n                  login\n                  avatarUrl(size: 40)\n                  url\n                }\n              }\n            }\n          }\n        }\n      }\n      files(first: $filesFirst) {\n        totalCount\n        nodes {\n          additions\n          deletions\n          changeType\n          path\n          viewerViewedState\n        }\n      }\n      author {\n        login\n        avatarUrl(size: 40)\n        url\n      }\n      assignees(first: 5) {\n        nodes {\n          id\n          login\n          avatarUrl(size: 40)\n          url\n        }\n      }\n      reviewRequests(first: 10) {\n        totalCount\n        nodes {\n          asCodeOwner\n          requestedReviewer {\n            __typename\n            ... on User {\n              id\n              login\n              avatarUrl(size: 40)\n              url\n            }\n            ... on Team {\n              id\n              combinedSlug\n            }\n            ... on Bot {\n              id\n              login\n              avatarUrl(size: 40)\n              url\n            }\n            ... on Mannequin {\n              id\n              login\n            }\n          }\n        }\n      }\n      reviews(first: $reviewsFirst) {\n        totalCount\n        nodes {\n          id\n          state\n          body\n          submittedAt\n          comments {\n            totalCount\n          }\n          author {\n            login\n            avatarUrl(size: 40)\n            url\n          }\n        }\n      }\n      reviewThreads(first: $threadsFirst) {\n        totalCount\n        nodes {\n          id\n          isResolved\n          isOutdated\n          path\n          comments(first: 10) {\n            nodes {\n              id\n              body\n              createdAt\n              diffHunk\n              author {\n                login\n                avatarUrl(size: 40)\n                url\n              }\n            }\n          }\n        }\n      }\n      closingIssuesReferences(first: 5) {\n        nodes {\n          id\n          number\n          title\n          url\n          state\n        }\n      }\n    }\n  }\n}": typeof types.PullRequestDetailDocument;
  'query RepositoryDetail($owner: String!, $name: String!, $rootExpression: String!, $readmeExpression: String!) {\n  repository(owner: $owner, name: $name) {\n    id\n    name\n    nameWithOwner\n    url\n    description\n    homepageUrl\n    createdAt\n    updatedAt\n    pushedAt\n    isPrivate\n    visibility\n    viewerPermission\n    stargazerCount\n    forkCount\n    watchers {\n      totalCount\n    }\n    issues(states: OPEN) {\n      totalCount\n    }\n    pullRequests(states: OPEN) {\n      totalCount\n    }\n    primaryLanguage {\n      name\n      color\n    }\n    languages(first: 6, orderBy: {field: SIZE, direction: DESC}) {\n      edges {\n        size\n        node {\n          id\n          name\n          color\n        }\n      }\n    }\n    owner {\n      __typename\n      login\n      ... on User {\n        name\n      }\n      ... on Organization {\n        name\n      }\n    }\n    defaultBranchRef {\n      name\n      target {\n        __typename\n        ... on Commit {\n          history(first: 1) {\n            totalCount\n          }\n          committedDate\n          messageHeadline\n          author {\n            name\n            user {\n              login\n              avatarUrl(size: 40)\n              url\n            }\n          }\n        }\n      }\n    }\n    refs(\n      refPrefix: "refs/heads/"\n      first: 10\n      orderBy: {field: ALPHABETICAL, direction: ASC}\n    ) {\n      totalCount\n      nodes {\n        id\n        name\n        target {\n          __typename\n          ... on Commit {\n            committedDate\n            messageHeadline\n            author {\n              name\n              user {\n                login\n              }\n            }\n          }\n        }\n      }\n    }\n    rootEntries: object(expression: $rootExpression) {\n      __typename\n      ... on Tree {\n        entries {\n          name\n          type\n          oid\n          mode\n          object {\n            __typename\n            ... on Blob {\n              byteSize\n              isBinary\n            }\n          }\n        }\n      }\n    }\n    readme: object(expression: $readmeExpression) {\n      __typename\n      ... on Blob {\n        byteSize\n        isBinary\n        text\n      }\n    }\n  }\n}': typeof types.RepositoryDetailDocument;
