  "query ViewerProfile($from: DateTime!, $to: DateTime!) {\n  viewer {\n    id\n    login\n    name\n    avatarUrl(size: 160)\n    url\n    email\n    company\n    location\n    websiteUrl\n    bio\n    createdAt\n    followers {\n      totalCount\n    }\n    following {\n      totalCount\n    }\n    organizations(first: 10) {\n      totalCount\n      nodes {\n        id\n        login\n        name\n        url\n        avatarUrl(size: 40)\n      }\n    }\n    repositories(\n      first: 5\n      affiliations: [OWNER, COLLABORATOR, ORGANIZATION_MEMBER]\n      orderBy: {field: PUSHED_AT, direction: DESC}\n      isFork: false\n    ) {\n      totalCount\n      nodes {\n        id\n        name\n        nameWithOwner\n        url\n        viewerPermission\n        updatedAt\n        isPrivate\n      }\n    }\n    contributionsCollection(from: $from, to: $to) {\n      totalCommitContributions\n      totalPullRequestContributions\n      totalIssueContributions\n      totalPullRequestReviewContributions\n    }\n  }\n}": typeof types.ViewerProfileDocument;
